type trackRequest struct {
	Tenant    string  `json:"tenant"`
	User      string  `json:"user"`
	Route     string  `json:"route"`
	Method    string  `json:"method"`
	Status    int     `json:"status"`
	RequestID string  `json:"request_id"`
	Attrs     string  `json:"attrs"`
	LatencyMS float64 `json:"latency_ms"`
	Bytes     int64   `json:"bytes"`
	Inflight  bool    `json:"inflight"`
}

func (a *App) handleTrack(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		w.WriteHeader(http.StatusMethodNotAllowed)
		return
	}

	var tr trackRequest
	dec := json.NewDecoder(http.MaxBytesReader(w, r.Body, 1<<20))
	dec.DisallowUnknownFields()
	if err := dec.Decode(&tr); err != nil {
		http.Error(w, "invalid json: "+err.Error(), http.StatusBadRequest)
		return
	}

	if tr.Method == "" {
		tr.Method = r.URL.Query().Get("method")
	}
	if tr.Route == "" {
		tr.Route = r.URL.Query().Get("route")
	}
	if tr.User == "" {
		tr.User = r.URL.Query().Get("user")
	}
	if tr.Tenant == "" {
		tr.Tenant = r.URL.Query().Get("tenant")
	}
	if tr.RequestID == "" {
		tr.RequestID = r.URL.Query().Get("request_id")
	}
	if tr.Attrs == "" {
		tr.Attrs = r.URL.Query().Get("attrs")
	}
	if tr.Status == 0 {
		if s := r.URL.Query().Get("status"); s != "" {
			if n, err := strconv.Atoi(s); err == nil {
				tr.Status = n
			}
		}
	}
	if tr.LatencyMS == 0 {
		if s := r.URL.Query().Get("latency_ms"); s != "" {
			if f, err := strconv.ParseFloat(s, 64); err == nil {
				tr.LatencyMS = f
			}
		}
	}
	if tr.Bytes == 0 {
		if s := r.URL.Query().Get("bytes"); s != "" {
			if n, err := strconv.ParseInt(s, 10, 64); err == nil {
				tr.Bytes = n
			}
		}
	}
	if !tr.Inflight {
		if s := r.URL.Query().Get("inflight"); s != "" {
			tr.Inflight = s == "1" || strings.EqualFold(s, "true") || strings.EqualFold(s, "yes")
		}
	}

	if tr.RequestID == "" {
		if rid, _ := r.Context().Value(ctxKeyRequestID{}).(string); rid != "" {
			tr.RequestID = rid
		} else {
			tr.RequestID = mustRandHex(8)
		}
	}

	a.observe(tr.Tenant, tr.User, tr.Route, tr.Method, tr.Status, tr.RequestID, tr.Attrs, time.Duration(tr.LatencyMS*float64(time.Millisecond)), tr.Bytes, tr.Inflight)

	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]any{
		"ok":         true,
		"request_id": tr.RequestID,
	})
}

func (a *App) handleWork(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	tenant := firstNonEmpty(r.URL.Query().Get("tenant"), r.Header.Get("X-Tenant-Id"))
	user := firstNonEmpty(r.URL.Query().Get("user"), r.Header.Get("X-User-Id"))
	route := firstNonEmpty(r.URL.Path, r.URL.Query().Get("route"))
	method := r.Method
	attrs := firstNonEmpty(r.URL.Query().Get("attrs"), r.Header.Get("X-Attrs"))

	reqID := r.URL.Query().Get("request_id")
	if reqID == "" {
		if rid, _ := r.Context().Value(ctxKeyRequestID{}).(string); rid != "" {
			reqID = rid
		} else {
			reqID = mustRandHex(8)
		}
	}

	sleepMS, _ := strconv.Atoi(r.URL.Query().Get("sleep_ms"))
	if sleepMS < 0 {
		sleepMS = 0
	}
	if sleepMS > 60000 {
		sleepMS = 60000
	}
	if sleepMS > 0 {
		time.Sleep(time.Duration(sleepMS) * time.Millisecond)
	}

	status := 200
	if s := r.URL.Query().Get("status"); s != "" {
		if n, err := strconv.Atoi(s); err == nil && n >= 100 && n <= 599 {
			status = n
		}
	}

	bytes := int64(len(r.URL.RawQuery))
	if b := r.URL.Query().Get("bytes"); b != "" {
		if n, err := strconv.ParseInt(b, 10, 64); err == nil {
			bytes = n
		}
	}

	a.observe(tenant, user, route, method, status, reqID, attrs, time.Since(start), bytes, false)

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(map[string]any{
		"tenant":     userOrUnknown(tenant),
		"user":       userOrUnknown(user),
		"route":      userOrUnknown(route),
		"method":     userOrUnknown(method),
		"status":     status,
		"request_id": reqID,
		"attrs":      userOrUnknown(attrs),
		"duration_ms": float64(time.Since(start)) / float64(time.Millisecond),
	})
}

func (a *App) observe(tenant, user, route, method string, status int, requestID, attrs string, dur time.Duration, bytes int64, inflightFlag bool) {
	statusStr := fmt.Sprintf("%d", status)

	a.mu.Lock()
	lt, lu, lr, lm, ls, lid, la, ok := a.limiter.AdmitAll(user, tenant, route, method, statusStr, requestID, attrs)
	if !ok {
		a.dropped.WithLabelValues("cardinality_limit").Inc()
	}
	a.mu.Unlock()

	if inflightFlag {
		a.inflight.WithLabelValues(lt, lu, lr, lm, lid, la).Inc()
		return
	}

	a.reqTotal.WithLabelValues(lt, lu, lr, lm, ls, lid, la).Inc()
	a.reqLatency.WithLabelValues(lt, lu, lr, lm, ls, lid, la).Observe(dur.Seconds())
	if bytes >= 0 {
		a.payload.WithLabelValues(lt, lu, lr, lm, ls, lid, la).Observe(float64(bytes))
	}
}

func firstNonEmpty(vs ...string) string {
	for _, v := range vs {
		if strings.TrimSpace(v) != "" {
			return v
		}
	}
	return ""
}

type ctxKeyRequestID struct{}
type ctxKeyRealIP struct{}

func withRequestID(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		rid := r.Header.Get("X-Request-Id")
		if rid == "" {
			rid = r.URL.Query().Get("request_id")
		}
		if rid == "" {
			rid = mustRandHex(8)
		}
		w.Header().Set("X-Request-Id", rid)
		ctx := context.WithValue(r.Context(), ctxKeyRequestID{}, rid)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

func withRealIP(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		ip := clientIP(r)
		ctx := context.WithValue(r.Context(), ctxKeyRealIP{}, ip)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

func clientIP(r *http.Request) string {
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			return strings.TrimSpace(parts[0])
		}
	}
	if xr := r.Header.Get("X-Real-Ip"); xr != "" {
		return strings.TrimSpace(xr)
	}
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err == nil && host != "" {
		return host
	}
	return r.RemoteAddr
}